/**
 * PR Prism GitHub Action - comment posting script
 *
 * reads cluster JSON from /tmp/prism-dupes.json (output of `prism dupes --json`),
 * checks if the current PR is in any cluster, and posts/updates a comment.
 *
 * env vars (set by the composite action):
 *   GITHUB_TOKEN - GitHub API token
 *   PR_NUMBER    - current PR number
 *   REPO         - owner/repo
 *   TOTAL_ITEMS  - total items scanned
 *   DUPE_PCT     - duplicate percentage
 */
import { readFileSync } from "node:fs";
async function run() {
    const token = process.env.GITHUB_TOKEN;
    const prNumber = parseInt(process.env.PR_NUMBER || "0", 10);
    const repo = process.env.REPO || "";
    const totalItems = parseInt(process.env.TOTAL_ITEMS || "0", 10);
    const dupePct = process.env.DUPE_PCT || "0";
    if (!token || !prNumber || !repo) {
        console.log("Missing required env vars (GITHUB_TOKEN, PR_NUMBER, REPO). Skipping comment.");
        return;
    }
    const [owner, repoName] = repo.split("/");
    if (!owner || !repoName) {
        console.log(`Invalid REPO format: ${repo}`);
        return;
    }
    // parse NDJSON cluster output
    let clusters;
    try {
        const raw = readFileSync("/tmp/prism-dupes.json", "utf-8").trim();
        if (!raw) {
            console.log("No duplicate data found. Skipping comment.");
            return;
        }
        clusters = raw
            .split("\n")
            .filter((line) => line.trim().startsWith("{"))
            .map((line) => JSON.parse(line));
    }
    catch (e) {
        console.log(`Failed to parse dupes output: ${e.message}`);
        return;
    }
    if (clusters.length === 0) {
        console.log("No duplicate clusters found. Skipping comment.");
        return;
    }
    // find clusters containing this PR
    const relevantClusters = clusters.filter((c) => c.items.some((i) => i.number === prNumber));
    if (relevantClusters.length === 0) {
        console.log(`PR #${prNumber} is not in any duplicate cluster. Skipping comment.`);
        return;
    }
    // build comment body
    let body = `## pr-prism triage\n\n`;
    body += `This PR appears in **${relevantClusters.length}** duplicate cluster(s).\n\n`;
    for (const cluster of relevantClusters) {
        const isBestPick = cluster.bestPick === prNumber;
        body += `### Cluster #${cluster.id} (${cluster.items.length} items, ${(cluster.avgSimilarity * 100).toFixed(0)}% avg similarity)\n\n`;
        if (isBestPick) {
            body += `> This PR is the **best pick** in this cluster.\n\n`;
        }
        else {
            body += `> Best pick: #${cluster.bestPick}\n\n`;
        }
        body += `| # | Title | Score |\n|---|-------|-------|\n`;
        for (const item of cluster.items.slice(0, 10)) {
            const marker = item.number === prNumber ? " **(this PR)**" : "";
            const best = item.number === cluster.bestPick ? " ★" : "";
            body += `| #${item.number}${best} | ${item.title.slice(0, 60)}${marker} | ${item.score.toFixed(2)} |\n`;
        }
        if (cluster.items.length > 10) {
            body += `| ... | +${cluster.items.length - 10} more | |\n`;
        }
        body += `\n`;
    }
    body += `---\n*${totalItems} items scanned, ${dupePct}% in duplicate clusters. Generated by [pr-prism](https://github.com/StressTestor/pr-prism)*`;
    // post or update comment via GitHub API
    const apiBase = `https://api.github.com/repos/${owner}/${repoName}`;
    const headers = {
        Authorization: `token ${token}`,
        Accept: "application/vnd.github.v3+json",
        "Content-Type": "application/json",
        "User-Agent": "pr-prism-action",
    };
    // check for existing comment
    const commentsResp = await fetch(`${apiBase}/issues/${prNumber}/comments?per_page=100`, { headers });
    if (!commentsResp.ok) {
        console.log(`Failed to fetch comments: ${commentsResp.status} ${commentsResp.statusText}`);
        return;
    }
    const comments = (await commentsResp.json());
    const existing = comments.find((c) => c.body?.includes("## pr-prism triage"));
    if (existing) {
        const updateResp = await fetch(`${apiBase}/issues/comments/${existing.id}`, {
            method: "PATCH",
            headers,
            body: JSON.stringify({ body }),
        });
        if (updateResp.ok) {
            console.log(`Updated existing pr-prism comment on #${prNumber}`);
        }
        else {
            console.log(`Failed to update comment: ${updateResp.status} ${updateResp.statusText}`);
        }
    }
    else {
        const createResp = await fetch(`${apiBase}/issues/${prNumber}/comments`, {
            method: "POST",
            headers,
            body: JSON.stringify({ body }),
        });
        if (createResp.ok) {
            console.log(`Posted pr-prism comment on #${prNumber}`);
        }
        else {
            console.log(`Failed to create comment: ${createResp.status} ${createResp.statusText}`);
        }
    }
}
run().catch((err) => {
    console.error(`Action failed: ${err.message || err}`);
    process.exit(1);
});
